const transcript = $input.item.json.transcript || '';

// Remove timestamps, clean formatting
const cleaned = transcript
  .replace(/\[\d{2}:\d{2}:\d{2}\]/g, '')
  .replace(/\s+/g, ' ')
  .replace(/[\r\n]+/g, ' ')
  .trim();

return {
  json: {
    videoId: $input.item.json.videoId,
    title: $input.item.json.title,
    transcript: cleaned,
    wordCount: cleaned.split(' ').length,
    duration: $input.item.json.duration
  }
};

