parameters.jsCode:
const blogContent = $input.item.json.choices?.[0]?.message?.content || '';

// Extract components using regex
const titleMatch = blogContent.match(/Title:\s*(.+?)\n/);
const metaMatch = blogContent.match(/Meta Description:\s*(.+?)\n/);

// Format as HTML
const htmlContent = blogContent
  .replace(/^##\s*(.+)$/gm, '<h2>$1</h2>')
  .replace(/^###\s*(.+)$/gm, '<h3>$1</h3>')
  .replace(/\n\n/g, '</p><p>')
  .replace(/^(.+)$/gm, '<p>$1</p>');

return {
  json: {
    type: 'blog',
    title: titleMatch ? titleMatch[1].trim() : 'Untitled',
    metaDescription: metaMatch ? metaMatch[1].trim() : '',
    content: htmlContent,
    wordCount: blogContent.split(' ').length,
    readTime: Math.ceil(blogContent.split(' ').length / 200) + ' min',
    publishReady: true
  }
};

const threadContent = $input.item.json.content?.[0]?.text || '';

// Split into individual tweets
const tweets = threadContent
  .split(/\n\d+\.\s+/)
  .filter(t => t.trim().length > 0)
  .map((tweet, index, array) => ({
    position: index + 1,
    total: array.length,
    content: tweet.trim().substring(0, 280),
    threadIndicator: `${index + 1}/${array.length}`,
    characterCount: tweet.trim().length
  }));

return {
  json: {
    type: 'twitter_thread',
    tweets: tweets,
    totalTweets: tweets.length,
    threadComplete: true,
    estimatedEngagement: tweets.length > 8 ? 'high' : 'medium'
  }
};

const content = $input.item.json.choices?.[0]?.message?.content || '';
const firstLine = content.split('\n')[0] || 'Key Insights';

// Format for LinkedIn
const linkedinPost = `🎯 ${firstLine}\n\n${content.substring(0, 2500)}\n\n💡 Key Takeaways:\n• Innovation drives growth\n• Customer focus wins\n• Data informs decisions\n\n👉 What's your take on this?\n\n#ContentMarketing #DigitalStrategy #YouTubeGrowth #ContentCreation`;

return {
  json: {
    type: 'linkedin',
    content: linkedinPost.substring(0, 3000),
    characterCount: linkedinPost.length,
    hashtagCount: (linkedinPost.match(/#/g) || []).length,
    hasEmojis: true,
    hasCTA: true
  }
};
